@using sv_d3f8aebd9488465aba0c3949b398d68a.Models

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in _sections)
        {
            <li class="nav-item">
                <button class="nav-link @(ActiveSection == section.Key ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
                    <span class="sidebar-icon">@section.Value.Icon</span>
                    <span>@section.Value.Label</span>
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private readonly Dictionary<string, (string Label, string Icon)> _sections = new()
    {
        ["Profile"] = ("Profile", "👤"),
        ["Notifications"] = ("Notifications", "🔔"),
        ["Security"] = ("Security", "🔒"),
        ["Appearance"] = ("Appearance", "🎨"),
    };
}

@using sv_d3f8aebd9488465aba0c3949b398d68a.Models

<div class="change-password-panel">
    <button class="btn btn-outline-secondary w-100 text-start d-flex justify-content-between align-items-center"
            @onclick="ToggleExpanded">
        <span>🔑 Change Password</span>
        <span>@(_expanded ? "▲" : "▼")</span>
    </button>

    @if (_expanded)
    {
        <div class="password-form mt-3">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(_error))
            {
                <div class="alert alert-danger py-2">@_error</div>
            }
            @if (_success)
            {
                <div class="alert alert-success py-2">Password updated successfully.</div>
            }

            <button class="btn btn-primary" @onclick="HandleUpdatePassword" disabled="@_saving">
                @(_saving ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _error;
    private bool _success;
    private bool _saving;

    private void ToggleExpanded() => _expanded = !_expanded;

    private async Task HandleUpdatePassword()
    {
        _error = null;
        _success = false;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _error = "Current password is required.";
            return;
        }
        if (_newPassword.Length < 6)
        {
            _error = "New password must be at least 6 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _error = "New passwords do not match.";
            return;
        }

        _saving = true;
        try
        {
            await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
            _success = true;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _saving = false;
        }
    }
}

@using sv_d3f8aebd9488465aba0c3949b398d68a.Models

@if (Visible && Session is not null)
{
    <div class="modal-backdrop show" @onclick="OnCancel"></div>
    <div class="modal d-block" tabindex="-1">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="OnCancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@Session.Device</strong> from <strong>@Session.Location</strong>?</p>
                    <p class="text-muted small">This will sign out the device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="OnCancel">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="OnConfirm">Revoke</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public ActiveSession? Session { get; set; }
    [Parameter] public bool Visible { get; set; }
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }
}

@using sv_d3f8aebd9488465aba0c3949b398d68a.Models

<div class="active-sessions-table">
    <h6>Active Sessions</h6>

    @if (Sessions is null || Sessions.Count == 0)
    {
        <p class="text-muted">No active sessions.</p>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-striped align-middle">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (session.Id != CurrentSessionId)
                                {
                                    <button class="btn btn-outline-danger btn-sm"
                                            @onclick="() => OnRevokeRequested.InvokeAsync(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="badge bg-success">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
</div>

@code {
    [Parameter] public List<ActiveSession>? Sessions { get; set; }
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter] public EventCallback<ActiveSession> OnRevokeRequested { get; set; }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

@using sv_d3f8aebd9488465aba0c3949b398d68a.Models

<div class="appearance-preview p-3 rounded border @ThemeClass()" style="font-size: @FontSizeValue();">
    <h6 class="mb-2">Live Preview</h6>
    <p class="mb-1"><strong>Theme:</strong> @(Settings?.Theme ?? "Light")</p>
    <div class="preview-card p-2 rounded mb-2">
        <p class="mb-1">This is a sample card showing how your selected settings look.</p>
        <button class="btn btn-sm btn-primary me-1">Primary</button>
        <button class="btn btn-sm btn-outline-secondary">Secondary</button>
    </div>
    <div class="d-flex gap-2 align-items-center">
        <span class="badge bg-info">Badge</span>
        <span class="text-muted small">Language: @(Settings?.Language ?? "English")</span>
        @if (Settings?.CompactMode == true)
        {
            <span class="badge bg-warning text-dark">Compact</span>
        }
    </div>
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }

    private string ThemeClass() => Settings?.Theme switch
    {
        "Dark" => "bg-dark text-light",
        "System" => "bg-secondary bg-opacity-10",
        _ => "bg-light text-dark"
    };

    private string FontSizeValue() => Settings?.FontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };
}

