@using sv_d3f8aebd9488465aba0c3949b398d68a.Models

<div class="appearance-preview p-3 rounded border @ThemeClass()" style="font-size: @FontSizeValue();">
    <h6 class="mb-2">Live Preview</h6>
    <p class="mb-1"><strong>Theme:</strong> @(Settings?.Theme ?? "Light")</p>
    <div class="preview-card p-2 rounded mb-2">
        <p class="mb-1">This is a sample card showing how your selected settings look.</p>
        <button class="btn btn-sm btn-primary me-1">Primary</button>
        <button class="btn btn-sm btn-outline-secondary">Secondary</button>
    </div>
    <div class="d-flex gap-2 align-items-center">
        <span class="badge bg-info">Badge</span>
        <span class="text-muted small">Language: @(Settings?.Language ?? "English")</span>
        @if (Settings?.CompactMode == true)
        {
            <span class="badge bg-warning text-dark">Compact</span>
        }
    </div>
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }

    private string ThemeClass() => Settings?.Theme switch
    {
        "Dark" => "bg-dark text-light",
        "System" => "bg-secondary bg-opacity-10",
        _ => "bg-light text-dark"
    };

    private string FontSizeValue() => Settings?.FontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };
}

