@using sv_d3f8aebd9488465aba0c3949b398d68a.Models

<div class="settings-section">
    <h4 class="mb-4">Profile</h4>

    @if (Profile is null)
    {
        <p class="text-muted">Loading profile…</p>
        return;
    }

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="_bio"></textarea>
            </div>
        </div>
        <div class="col-md-4">
            <div class="avatar-preview text-center">
                <img src="@Profile.AvatarUrl" alt="Avatar" class="rounded-circle mb-2"
                     style="width:100px;height:100px;object-fit:cover;" />
                <p class="text-muted small text-break">@Profile.AvatarUrl</p>
            </div>
        </div>
    </div>

    @if (_showSuccess)
    {
        <div class="alert alert-success py-2 mt-2">Profile saved successfully!</div>
    }

    <div class="d-flex gap-2 mt-3">
        <button class="btn btn-primary" @onclick="HandleSave" disabled="@_saving">
            @(_saving ? "Saving…" : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="DiscardChanges">
            Discard Changes
        </button>
    </div>
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private bool _saving;
    private bool _showSuccess;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !_initialized)
        {
            ResetFields();
            _initialized = true;
        }
    }

    private bool _initialized;

    private void ResetFields()
    {
        if (Profile is null) return;
        _displayName = Profile.DisplayName;
        _email = Profile.Email;
        _bio = Profile.Bio;
    }

    private void DiscardChanges()
    {
        ResetFields();
        _showSuccess = false;
    }

    private async Task HandleSave()
    {
        if (Profile is null) return;
        _saving = true;
        _showSuccess = false;

        var updated = Profile with
        {
            DisplayName = _displayName,
            Email = _email,
            Bio = _bio
        };

        await OnSave.InvokeAsync(updated);
        _showSuccess = true;
        _saving = false;
    }
}

@using sv_d3f8aebd9488465aba0c3949b398d68a.Models

<div class="settings-section">
    <h4 class="mb-4">Notifications</h4>

    @if (Prefs is null)
    {
        <p class="text-muted">Loading notification preferences…</p>
        return;
    }

    <div class="mb-4">
        <h6>Notification Channels</h6>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="emailNotif"
                   checked="@_emailNotifications"
                   @onchange="e => _emailNotifications = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="pushNotif"
                   checked="@_pushNotifications"
                   @onchange="e => _pushNotifications = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="weeklyDigest"
                   checked="@_weeklyDigest"
                   @onchange="e => _weeklyDigest = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <div class="mb-4">
        <h6>Muted Channels</h6>
        <p class="text-muted small">Uncheck a channel to receive notifications from it.</p>

        @foreach (var channel in _allChannels)
        {
            <div class="form-check mb-1">
                <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                       checked="@_mutedChannels.Contains(channel)"
                       @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                <label class="form-check-label" for="@($"ch-{channel}")">#@channel</label>
            </div>
        }
    </div>

    @if (_showSuccess)
    {
        <div class="alert alert-success py-2">Preferences saved!</div>
    }

    <button class="btn btn-primary" @onclick="HandleSave" disabled="@_saving">
        @(_saving ? "Saving…" : "Save Preferences")
    </button>
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private bool _saving;
    private bool _showSuccess;
    private bool _initialized;

    private readonly List<string> _allChannels =
        ["announcements", "general", "engineering", "random", "off-topic"];

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !_initialized)
        {
            _emailNotifications = Prefs.EmailNotifications;
            _pushNotifications = Prefs.PushNotifications;
            _weeklyDigest = Prefs.WeeklyDigest;
            _mutedChannels = new HashSet<string>(Prefs.MutedChannels);
            _initialized = true;
        }
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task HandleSave()
    {
        _saving = true;
        _showSuccess = false;

        var updated = new NotificationPrefs(
            _emailNotifications,
            _pushNotifications,
            _weeklyDigest,
            _mutedChannels.ToList());

        await OnSave.InvokeAsync(updated);
        _showSuccess = true;
        _saving = false;
    }
}

@using sv_d3f8aebd9488465aba0c3949b398d68a.Models

<div class="settings-section">
    <h4 class="mb-4">Security</h4>

    @if (Settings is null)
    {
        <p class="text-muted">Loading security settings…</p>
        return;
    }

    <div class="mb-4">
        <ChangePasswordPanel OnChangePassword="OnChangePassword" />
    </div>

    <div class="mb-4">
        <h6>Two-Factor Authentication</h6>
        <div class="d-flex align-items-center gap-3">
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="twoFactor"
                       checked="@Settings.TwoFactorEnabled" disabled />
                <label class="form-check-label" for="twoFactor">Two-Factor Authentication</label>
            </div>
            @if (Settings.TwoFactorEnabled)
            {
                <span class="badge bg-success">Enabled</span>
            }
            else
            {
                <span class="badge bg-warning text-dark">Disabled</span>
            }
        </div>
        @if (Settings.LastPasswordChange.HasValue)
        {
            <p class="text-muted small mt-2">
                Last password change: @Settings.LastPasswordChange.Value.ToString("MMMM d, yyyy")
            </p>
        }
    </div>

    <div class="mb-4">
        <ActiveSessionsTable Sessions="Settings.Sessions"
                             OnRevokeRequested="RequestRevoke" />
    </div>

    <RevokeSessionDialog Session="_sessionToRevoke"
                         Visible="_showRevokeDialog"
                         OnConfirm="ConfirmRevoke"
                         OnCancel="CancelRevoke" />
</div>

@code {
    [Parameter] public SecuritySettings? Settings { get; set; }
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private ActiveSession? _sessionToRevoke;
    private bool _showRevokeDialog;

    private void RequestRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await OnRevokeSession.InvokeAsync(_sessionToRevoke.Id);
        }
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }
}

@using sv_d3f8aebd9488465aba0c3949b398d68a.Models

<div class="settings-section">
    <h4 class="mb-4">Appearance</h4>

    @if (Settings is null)
    {
        <p class="text-muted">Loading appearance settings…</p>
        return;
    }

    <div class="row">
        <div class="col-md-6">
            <div class="mb-4">
                <h6>Theme</h6>
                @foreach (var theme in _themes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme"
                               id="@($"theme-{theme}")"
                               checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6>Font Size</h6>
                @foreach (var size in _fontSizes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="@($"fs-{size}")"
                               checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6>Language</h6>
                <select class="form-select" @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode"
                           checked="@_compactMode"
                           @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>

            @if (_showSuccess)
            {
                <div class="alert alert-success py-2">Appearance saved!</div>
            }

            <button class="btn btn-primary" @onclick="HandleSave" disabled="@_saving">
                @(_saving ? "Saving…" : "Save")
            </button>
        </div>

        <div class="col-md-6">
            <AppearancePreview Settings="@CurrentPreview" />
        </div>
    </div>
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _saving;
    private bool _showSuccess;
    private bool _initialized;

    private readonly string[] _themes = ["Light", "Dark", "System"];
    private readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    private AppearanceSettings CurrentPreview => new(_theme, _fontSize, _language, _compactMode);

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_initialized)
        {
            _theme = Settings.Theme;
            _fontSize = Settings.FontSize;
            _language = Settings.Language;
            _compactMode = Settings.CompactMode;
            _initialized = true;
        }
    }

    private async Task HandleSave()
    {
        _saving = true;
        _showSuccess = false;

        await OnSave.InvokeAsync(CurrentPreview);
        _showSuccess = true;
        _saving = false;
    }
}

