@page "/settings"
@using sv_d3f8aebd9488465aba0c3949b398d68a.Models
@rendermode InteractiveServer
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@_activeSection"
                     OnSectionChanged="section => _activeSection = section" />

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection Profile="_profile" OnSave="SaveProfile" />
                break;
            case "Notifications":
                <NotificationsSection Prefs="_notificationPrefs" OnSave="SaveNotifications" />
                break;
            case "Security":
                <SecuritySection Settings="_securitySettings"
                                 OnChangePassword="HandleChangePassword"
                                 OnRevokeSession="HandleRevokeSession" />
                break;
            case "Appearance":
                <AppearanceSection Settings="_appearance" OnSave="SaveAppearance" />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";
    private UserProfile? _profile;
    private NotificationPrefs? _notificationPrefs;
    private SecuritySettings? _securitySettings;
    private AppearanceSettings? _appearance;

    protected override async Task OnInitializedAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        _profile = profileTask.Result;
        _notificationPrefs = notifTask.Result;
        _securitySettings = securityTask.Result;
        _appearance = appearanceTask.Result;
    }

    private async Task SaveProfile(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        _profile = profile;
    }

    private async Task SaveNotifications(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _notificationPrefs = prefs;
    }

    private async Task HandleChangePassword((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task HandleRevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task SaveAppearance(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        _appearance = settings;
    }
}

.settings-dashboard {
    display: flex;
    gap: 2rem;
    min-height: 70vh;
}

/* Sidebar */
::deep .settings-sidebar {
    min-width: 200px;
    max-width: 220px;
    border-right: 1px solid #dee2e6;
    padding-right: 1rem;
}

::deep .sidebar-title {
    font-weight: 600;
    padding: 0.5rem 0.75rem;
    margin-bottom: 0.5rem;
    color: #495057;
}

::deep .settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.6rem 0.75rem;
    border-radius: 0.375rem;
    color: #495057;
    background: none;
    border: none;
    width: 100%;
    text-align: left;
    cursor: pointer;
    transition: background-color 0.15s;
}

::deep .settings-sidebar .nav-link:hover {
    background-color: #e9ecef;
}

::deep .settings-sidebar .nav-link.active {
    background-color: #0d6efd;
    color: white;
}

::deep .sidebar-icon {
    font-size: 1.1rem;
}

/* Content area */
.settings-content {
    flex: 1;
    min-width: 0;
}

::deep .settings-section {
    max-width: 800px;
}

/* Avatar preview */
::deep .avatar-preview {
    padding: 1rem;
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    background: #f8f9fa;
}

/* Password panel */
::deep .change-password-panel {
    max-width: 500px;
}

::deep .password-form {
    padding: 1rem;
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    background: #f8f9fa;
}

/* Appearance preview */
::deep .appearance-preview {
    transition: all 0.2s ease;
}

::deep .appearance-preview .preview-card {
    background: rgba(0, 0, 0, 0.05);
    border: 1px solid rgba(0, 0, 0, 0.1);
}

::deep .bg-dark .preview-card {
    background: rgba(255, 255, 255, 0.1);
    border: 1px solid rgba(255, 255, 255, 0.15);
}

/* Modal backdrop */
::deep .modal-backdrop {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    z-index: 1040;
}

::deep .modal.d-block {
    z-index: 1050;
}

